import{_ as s,o as i,c as t,a0 as a}from"./chunks/framework.DgPozsi0.js";const o="/vitepress-study/assets/nextDev_01_06_01.BuvBGtAs.avif",r="/vitepress-study/assets/nextDev_01_06_02.4HYQ9K2d.avif",l="/vitepress-study/assets/nextDev_01_06_03.BBE2t_FA.avif",c="/vitepress-study/assets/nextDev_01_06_04.Bpcaucha.avif",n="/vitepress-study/assets/nextDev_01_06_05.CWIFmuEx.avif",_=JSON.parse('{"title":"[Next.js官網] Next.js 16.2 教程","description":"","frontmatter":{"title":"[Next.js官網] Next.js 16.2 教程"},"headers":[],"relativePath":"pages/f2e/docReact/nextDev/01/nextDev_01_06.md","filePath":"pages/f2e/docReact/nextDev/01/nextDev_01_06.md"}'),d={name:"pages/f2e/docReact/nextDev/01/nextDev_01_06.md"};function p(h,e,k,u,g,b){return i(),t("div",null,[...e[0]||(e[0]=[a('<h1 id="設定資料庫" tabindex="-1">設定資料庫 <a class="header-anchor" href="#設定資料庫" aria-label="Permalink to &quot;設定資料庫&quot;">​</a></h1><p>在你能繼續開發儀表板之前，你需要一些資料。在本章中，你將透過 <a href="https://vercel.com/marketplace?category=storage" target="_blank" rel="noreferrer">Vercel 市集整合服務</a> 之一來設定一個 <code>PostgreSQL</code> 資料庫。如果你已經熟悉 <code>PostgreSQL</code>，並偏好使用自己的資料庫供應商，你可以跳過本章，自行設定資料庫。否則，讓我們繼續吧！</p><div class="info custom-block"><p class="custom-block-title"><strong>本章內容</strong></p><p>以下是本章將涵蓋的主題：</p><ul><li>將你的專案推送到 <code>GitHub</code>。</li><li>設定 <code>Vercel</code> 帳號，並連結你的 <code>GitHub repo</code>，以取得即時預覽與部署功能。</li><li>建立資料庫，並將專案與 <code>Postgres</code> 資料庫連結。</li><li>為資料庫植入初始資料。</li></ul></div><h2 id="建立-github-repository" tabindex="-1">建立 GitHub Repository <a class="header-anchor" href="#建立-github-repository" aria-label="Permalink to &quot;建立 GitHub Repository&quot;">​</a></h2><ul><li><p>首先，如果你還沒這麼做，讓我們先將你的 <code>repository</code> 推送到 <code>GitHub</code>。這會讓你更容易設定資料庫並進行部署。</p></li><li><p>如果你需要協助設定 <code>repository</code>，可以參考 <a href="https://help.github.com/en/github/getting-started-with-github/create-a-repo" target="_blank" rel="noreferrer">這篇 GitHub 上的指南</a>。</p></li></ul><blockquote><p><strong>小提醒：</strong></p><ul><li>你也可以使用其他 git 供應商，例如 <code>GitLab</code> 或 <code>Bitbucket</code>。</li><li>如果你是 <code>GitHub</code> 新手，我們建議使用 <a href="https://desktop.github.com/" target="_blank" rel="noreferrer">GitHub Desktop App</a>，讓開發流程更簡化。</li></ul></blockquote><h2 id="建立-vercel-帳號" tabindex="-1">建立 Vercel 帳號 <a class="header-anchor" href="#建立-vercel-帳號" aria-label="Permalink to &quot;建立 Vercel 帳號&quot;">​</a></h2><ul><li>前往 <a href="https://vercel.com/signup" target="_blank" rel="noreferrer">vercel.com/signup</a> 建立帳號。選擇免費的「<code>hobby</code>」方案。選取 <strong>Continue with GitHub</strong>，將你的 <code>GitHub</code> 帳號與 <code>Vercel</code> 帳號連結。</li></ul><h2 id="連結並部署你的專案" tabindex="-1">連結並部署你的專案 <a class="header-anchor" href="#連結並部署你的專案" aria-label="Permalink to &quot;連結並部署你的專案&quot;">​</a></h2><ul><li><p>接著，你會被帶到以下畫面，你可以在此選取並 <strong>匯入（import）</strong> 剛剛建立好的 <code>GitHub repository</code>：</p><p><img src="'+o+'" alt="Vercel 儀表板畫面截圖，顯示匯入專案畫面，並列出使用者的 GitHub Repositories 清單"></p></li><li><p>為你的專案命名，然後點擊 <strong>Deploy</strong>。</p><p><img src="'+r+'" alt="部署畫面，顯示專案名稱欄位與部署按鈕"></p></li><li><p>太棒了！ 你的專案現在已經部署完成。</p><p><img src="'+l+'" alt="專案總覽畫面，顯示專案名稱、網域與部署狀態"></p></li><li><p>透過連結你的 <code>GitHub repository</code>，之後每當你將變更推送到 <strong>main</strong> 分支時，<code>Vercel</code> 就會自動重新部署你的應用程式，完全不需要額外設定。當你開啟 <code>pull request</code> 時，你也會取得<a href="https://vercel.com/docs/deployments/environments#preview-environment-pre-production#preview-urls" target="_blank" rel="noreferrer">即時預覽網址</a>，讓你能及早發現部署錯誤，並將專案預覽分享給團隊成員以收集回饋意見。</p></li></ul><h2 id="建立-postgres-資料庫" tabindex="-1">建立 Postgres 資料庫 <a class="header-anchor" href="#建立-postgres-資料庫" aria-label="Permalink to &quot;建立 Postgres 資料庫&quot;">​</a></h2><ul><li><p>接下來，要設定資料庫，請點擊 <code>Continue to Dashboard</code>，並在專案儀表板中選取 <code>Storage</code> 分頁。選取 <code>Create Database</code>。依照你建立 <code>Vercel</code> 帳號的時間點不同，你可能會看到像 <code>Neon</code> 或 <code>Supabase</code> 這類選項。選擇你偏好的供應商，然後點擊 <code>Continue</code>。</p><p><img src="'+c+'" alt="連結儲存空間畫面，顯示 Postgres 選項，以及 KV、Blob 與 Edge Config 等選項"></p></li><li><p>如有需要，選擇你的地區與儲存方案。所有 <code>Vercel</code> 專案的 <a href="https://vercel.com/docs/functions/configuring-functions/region" target="_blank" rel="noreferrer">預設地區</a> 為 <code>Washington D.C（iad1）</code>，如果可以選擇，我們建議選用這個地區，以降低資料請求的 <a href="https://developer.mozilla.org/en-US/docs/Web/Performance/Understanding_latency" target="_blank" rel="noreferrer">延遲（latency）</a>。</p><p><img src="'+n+`" alt="資料庫建立視窗，顯示資料庫名稱與地區欄位"></p></li><li><p>連結完成後，切換到 <code>.env.local</code> 分頁，點擊 <code>Show secret</code>，再點擊 <code>Copy Snippet</code>。請務必先顯示這些機密資料（secrets），再進行複製。</p></li><li><p>前往你的程式碼編輯器，將 <code>.env.example</code> 檔案重新命名為 <code>.env</code> 。將你剛剛從 <code>Vercel</code> 複製的內容貼上。</p><blockquote><p><strong>重要：</strong> 前往你的 <code>.gitignore</code> 檔案，並確認 <code>.env</code> 已列在忽略清單中，以避免你在推送到 <code>GitHub</code> 時，不小心洩露資料庫的機密資料。</p></blockquote></li></ul><h2 id="為資料庫植入資料" tabindex="-1">為資料庫植入資料 <a class="header-anchor" href="#為資料庫植入資料" aria-label="Permalink to &quot;為資料庫植入資料&quot;">​</a></h2><ul><li><p>現在資料庫已經建立完成，讓我們為它植入一些初始資料。</p></li><li><p>我們已經提供了一組可以在瀏覽器中存取的 <code>API</code>，它會執行一個植入資料的腳本（<code>seed script</code>），將初始資料填入資料庫中。</p></li><li><p>這個腳本會使用 <code>SQL</code> 來建立資料表，並在資料表建立完成後，使用 <code>placeholder-data.ts</code> 檔案中的資料來填入這些資料表。</p></li><li><p>請確認你的本機開發伺服器正透過 <code>pnpm run dev</code> 執行中，並在瀏覽器中前往 <a href="http://localhost:3000/seed" target="_blank" rel="noreferrer"><code>localhost:3000/seed</code></a>。完成後，你會在瀏覽器中看到「<code>Database seeded successfully</code>」的訊息。完成之後，你可以刪除這個檔案。</p><blockquote><p><strong>疑難排解：</strong></p><ul><li>請務必先顯示你的資料庫機密資料，再將其複製到 <code>.env</code> 檔案中。</li><li>這個腳本使用 <code>bcrypt</code> 來對使用者的密碼進行雜湊處理（hash），如果 <code>bcrypt</code> 與你的環境不相容，你可以將腳本改為使用 <a href="https://www.npmjs.com/package/bcryptjs" target="_blank" rel="noreferrer"><code>bcryptjs</code></a>。</li><li>如果你在植入資料庫的過程中遇到任何問題，想要重新執行腳本，可以在資料庫查詢介面中執行 <code>DROP TABLE tablename</code> 指令，刪除既有的資料表。詳情請參考下方的 <a href="#executing-queries">執行查詢</a> 段落。但請小心，這個指令會刪除資料表以及其中的所有資料。在這個範例應用程式中這樣做沒有問題，因為你使用的是佔位資料，但在正式環境的應用程式中，你「不應該」執行這個指令。</li></ul></blockquote></li></ul><h2 id="執行查詢" tabindex="-1">執行查詢 <a class="header-anchor" href="#執行查詢" aria-label="Permalink to &quot;執行查詢&quot;">​</a></h2><ul><li><p>讓我們執行一個查詢，確認一切運作正常。我們會使用另一個 Router Handler：<code>app/query/route.ts</code>，來查詢資料庫。在這個檔案中，你會找到一個 <code>listInvoices()</code> 函式，其中包含以下的 <code>SQL</code> 查詢：</p><div class="language-sql vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">sql</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">SELECT</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> invoices</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">.</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">amount</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">customers</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">.</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">name</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">FROM</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> invoices</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">JOIN</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> customers </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">ON</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> invoices</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">.</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">customer_id</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> =</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> customers</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">.</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">id</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">WHERE</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> invoices</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">.</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">amount</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> =</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 666</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div></li><li><p>取消該檔案的註解，移除 <code>Response.json() block</code>，並在瀏覽器中前往 <a href="http://localhost:3000/query" target="_blank" rel="noreferrer"><code>localhost:3000/query</code></a>。你應該會看到系統回傳了一筆發票的 <code>amount</code> 與 <code>name</code>。</p></li></ul>`,16)])])}const v=s(d,[["render",p]]);export{_ as __pageData,v as default};
